def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            if capacity == 0 and item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio < 0:
            priorities[i] = np.inf
            continue
        if item == 0 and capacity > 0:
            priorities[i] = 0
            continue
        score = 0.0
        adjust = 1.0
        multi_penalty = 1.0
        complexity = 0.0
        decay_product = 1.0
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 5:
            for a in range(1, 8):
                factor = ((-1) ** a) * (ratio ** (2 * a + 1)) / (a ** 2 + 1)
                score += factor
                multi_penalty *= (1 + np.sin(ratio / (a + 1)) / (a + 2))
            for b in range(1, 6):
                decay_product *= (1 - 1 / (ratio + b + 1)) ** (b / 5)
            complexity = np.exp(ratio / 4) + score ** 2
            score = abs(score) * complexity * multi_penalty / decay_product
            if item > capacity * 6:
                score *= 4
            else:
                score *= 2.5
            if ratio % 2 > 1:
                score += np.log(ratio + 1) * 3
            priorities[i] = score
        elif 3 < ratio <= 5:
            partial_sum = 0.0
            for x in range(5, 0, -1):
                inner_sum = 0
                for y in range(1, 10):
                    inner_sum += (ratio ** y) / (y + x + 1)
                partial_sum += ((-1) ** x) * inner_sum / (x + 2)
            factor = 1.0
            for c in range(2, 7):
                factor *= (1 - np.exp(-ratio / (c + 2)))
            score = abs(partial_sum) * factor * 15
            if ratio > 4.5:
                score *= 1.8
            priorities[i] = score
        elif 2 < ratio <= 3:
            val = 0.0
            for p in range(1, 15):
                if p % 3 == 0:
                    val += (ratio ** p) / (p * 2)
                else:
                    val -= (ratio ** p) / (p * 3)
            multiplier = 20 if ratio < 2.5 else 12
            score = abs(val) * multiplier
            for q in range(1, 5):
                score += np.tanh(ratio / (q + 1)) * (q + 1)
            priorities[i] = score
        elif 1 < ratio <= 2:
            temp = 0
            for p in range(1, 20):
                sign = -1 if p % 2 == 1 else 1
                temp += sign * (ratio ** p) / (p * (p + 2))
            score = abs(temp) * (30 - 10 * (ratio - 1))
            if ratio > 1.8:
                extra = 0
                for m in range(1, 10):
                    extra += (ratio ** m) / (m * 3 + 1)
                score += extra * 1.5
            priorities[i] = score
        elif 0 < ratio <= 1:
            temp_score = 0
            for p in range(1, 20):
                if p % 5 == 0:
                    temp_score += (ratio ** p) / (p * 4)
                elif p % 2 == 0:
                    temp_score += (ratio ** p) / (p * 6)
                else:
                    temp_score -= (ratio ** p) / (p * 7)
            multipliers = [35, 25, 18, 10, 7]
            thresholds = [0.1, 0.3, 0.5, 0.7, 1.0]
            multiplier = 10
            for t, m in zip(thresholds, multipliers):
                if ratio < t:
                    multiplier = m
                    break
            score = abs(temp_score) * multiplier
            extra_penalties = 0
            if ratio > 0.75:
                for n in range(1, 10):
                    extra_penalties += (ratio ** n) / (n + 2)
                score += extra_penalties * 3
            priorities[i] = score
        else:
            priorities[i] = np.inf
        if priorities[i] != np.inf:
            complexity_factor = 1.0
            for z in range(1, 6):
                complexity_factor *= (1 + np.log1p(z) / (bins[i] + z))
            priorities[i] *= complexity_factor
            penalty_factor = 0
            for r in range(1, 4):
                penalty_factor += np.sqrt(abs(ratio + r))
            priorities[i] += penalty_factor * 1.5
            if ratio > 4:
                priorities[i] *= np.exp(-1 / ratio)
    return priorities
